---播放移动
---@class LBattleSkillActMove
local LBattleSkillActMove = classX("LBattleSkillActMove", nil)

---@param player LBattleSkillPlayer
---@param effData LSkillEffectData
---@param playState LBattleSkillPlayState
function LBattleSkillActMove.GetOneTargetExcludeSelf(player, effData, playState)
    local ignoreAllBeHtMap = player:GetIgnoreAllBeHtMap()
    local _recordPosOnHookIdMap = player:GetRecordPosOnHookIdMap()

    local _isPosOnHook = player:IsPosOnHook()

    --获取一个符合的目标,最起码不是自己
    local skillHurtData = player:GetSkillHurtDataList() or {}
    local id = nil
    for k,v in ipairs(skillHurtData) do
        for k1,v1 in ipairs(v) do
            if v1.hitHurt then
                if _isPosOnHook then
                    local ht = v1.hitHurt.ht
                    if ht and ht > 0 and not ignoreAllBeHtMap[ht] then
                        local tempTab = _recordPosOnHookIdMap[v1.hitHurt.eId]
                        if not tempTab or not tempTab[effData.effType] then
                            id = v1.hitHurt.eId
                            if not tempTab then
                                tempTab = {}
                                _recordPosOnHookIdMap[id] = tempTab
                            end
                            tempTab[effData.effType] = true
                            break
                        end
                    end
                else
                    id = v1.hitHurt.eId
                end
            end

            if id ~= nil then break end
        end

        if id ~= nil then break end
    end

    return id
end



---@param player LBattleSkillPlayer
---@param effData LSkillEffectData
function LBattleSkillActMove.Execute(player,effData)
    local obj = player:GetTargetAtkUnitView()

    local moveTime = effData.playTime
    local effTarget = effData.effTarget
    local bulletTrack = effData.bulletTrack
    local offset = effData.effOffsetEnd
    local effOffsetStart = effData.effOffsetStart
    local tarPos = Vector3.zero
    local atkPos = obj:GetPosition()

    local tarObj = nil

    local viewMgr = player:GetViewMgr()

    local atkUnitView = player:GetAtkUnitView()

    local skillHurtData = player:GetSkillHurtDataList()

    local id = LBattleSkillActMove.GetOneTargetExcludeSelf(player, effData)
    if id then
        tarObj = viewMgr:GetUnitView(id)
    end

    if effTarget == LFightConst.PLAY_MOVE_TO_TARGET then
        tarPos = tarObj and tarObj:GetGridPos() or viewMgr:GetFormationCenterPoint()
    elseif effTarget == LFightConst.PLAY_MOVE_TO_CENTER then
        tarPos = viewMgr:GetFormationCenterPoint()
    elseif effTarget == LFightConst.PLAY_MOVE_TO_BACK then
        tarPos = obj:GetGridPos()
    elseif effTarget == LFightConst.PLAY_MOVE_TO_SCREEN_OUTSIDE then
        local pos = obj:GetGridPos()
        local startX = player:GetBoneOffset()
        tarPos = obj:GetTeamIdx() == 1 and Vector3(-startX,pos.y,0) or Vector3(startX,pos.y,0)

    elseif effTarget == LFightConst.EFFECT_TO_ENEMY_TEAM_COLUMN then
        --5=敌方目标所在列战场中心
        if not tarObj then
            if LOG_INFO_ENABLED then
                LogError(string.format("战报中未找到目标 %s",id))
            end
            return
        end
        local pos = tarObj:GetGridPos():Clone()
        tarPos = Vector3(0,pos.y,0)
    elseif effTarget == LFightConst.PLAY_SELF_CENTER then --己方九宫中心
        tarPos = viewMgr:GetFormationCenterPosition(obj:GetTeamIdx()):Clone()
    elseif effTarget == LFightConst.PLAY_OTHER_CENTER then --敌方九宫中心
        local side = viewMgr:GetOppositeSide(obj:GetTeamIdx())
        tarPos = viewMgr:GetFormationCenterPosition(side):Clone()
    elseif effTarget == LFightConst.PLAY_MOVE_SOLID then --固定偏移
        tarPos = atkPos

    elseif effTarget == LFightConst.PLAY_MOVE_ROW_CENTER then
        --9=目标排中心
        -- 选择下标最小的
        local selMinGrid
        local tempGrid = 1
        for k, v in ipairs(skillHurtData) do
            for k1,v1 in ipairs(v) do
                if v1.hitHurt then
                    local tempTarObj = viewMgr:GetUnitView(v1.hitHurt.eId)
                    tempGrid = tempTarObj:GetIndex()
                    if not selMinGrid then
                        selMinGrid = tempGrid
                    elseif selMinGrid > tempGrid then
                        selMinGrid = tempGrid
                    end
                end
            end
        end
        if selMinGrid and selMinGrid > 0 then
            local side = viewMgr:GetOppositeSide(obj:GetTeamIdx())
            tarPos = viewMgr:GetRowCenterPos(side,selMinGrid)
        end

    end

    local isInSitu = effTarget == LFightConst.PLAY_MOVE_TO_INSITU
    local pos = Vector3(tarPos.x, tarPos.y + offset.y, 0)
    if not isInSitu then
        local side = obj:GetTeamIdx()
        local offsetX = nil
        if effTarget == LFightConst.PLAY_MOVE_SOLID then
            if side == BattleTeamSide.teamA then
                offsetX =  offset.x
            else
                offsetX = - offset.x
            end
        else
            if side == BattleTeamSide.teamA then
                offsetX = - offset.x
            else
                offsetX = offset.x
            end
        end

        pos.x = pos.x + offsetX
    end

    --动作名字
    local ani = effData.effRes
    if ani and not string.isempty(ani) then
        moveTime = effData.actionReset == 0 and moveTime or 0
        obj:PlayAni(ani, false, moveTime)
    end

    if isInSitu then
        obj:StartInSitu(effData)
        return
    end

    if bulletTrack == LFightConst.BATTLE_LINEAR then
        obj:StartMove(pos, moveTime,true)
    elseif bulletTrack == LFightConst.BATTLE_CURVE_ONE then
        local topPosX = Mathf.Lerp(atkPos.x, pos.x,  2 / 3)
        local topPosY = atkPos.y + effOffsetStart.y
        local topPos = Vector3(topPosX,topPosY,0)
        obj:StartJumpTo(pos, topPos, moveTime, 0)
    elseif bulletTrack == LFightConst.BATTLE_CURVE_TWO then
        local startPos = pos + Vector3.New(0,10,0)
        obj:SetPosition(startPos)
        local direction = LFightConst.DIRECTION_LEFT
        if atkUnitView:GetTeamType() == BattleTeamSide.teamA then
            direction = LFightConst.DIRECTION_RIGHT
        end
        obj:SetDirection(direction)
        obj:StartMove(pos,moveTime)
    elseif bulletTrack == LFightConst.BATTLE_CURVE_THREE then
        obj:StartFade(moveTime)
    end

end

return LBattleSkillActMove